import { useClipboard } from '@chakra-ui/react';
import { PublicActionPage } from '@domain/publicActionPage';
import { useGetAllCustomDomains } from '@state/customDomains';
import { getEventPageURLByString } from '@utils/getEventPageUrl';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '../Button';
import { InputControl } from '../InputControl';
import { CloseIcon, FacebookShareIcon, LinkedInShareIcon, ShareIcon, XShareIcon } from '../icons';
import { Paragraph } from '../Paragraph';
import { Popover, PopoverClose, PopoverContent, PopoverTrigger } from '../Popover';

const SHARE_ICON_CLASSES =
  'flex h-[64px] w-[64px] items-center justify-center rounded-full border border-neutral-300 p-1';

export const ShareButtons = ({
  actionPage,
  isPreview,
}: {
  actionPage: PublicActionPage;
  isPreview: boolean;
}) => {
  const { t } = useTranslation('actionPagesBuilder');
  const { customDomains } = useGetAllCustomDomains({});
  const previewEventUrl = getEventPageURLByString(
    actionPage?.account?.slug || '',
    actionPage?.slug ?? actionPage?.id ?? '',
    customDomains,
    actionPage?.defaultSourceCode
  );

  const eventUrl = isPreview ? previewEventUrl : window.location.href;
  const encodedEventUrl = encodeURIComponent(eventUrl);
  const { hasCopied: hasCopiedPageUrl, onCopy: onCopyPageURL } = useClipboard(eventUrl);

  const {
    facebookSocialShareDescription,
    facebookSocialShareTitle,
    twitterSocialShareDescription,
    twitterSocialShareTitle,
  } = actionPage;

  // Facebook pulls the title, description, and image from the page's Open Graph meta tags when sharing a link.
  // See ActionPageSEO.tsx for meta tags
  const handleFacebookShare = useCallback(() => {
    const facebookShareURL = `https://www.facebook.com/sharer/sharer.php?u=${encodedEventUrl}`;
    window.open(facebookShareURL, '_blank');
  }, [encodedEventUrl]);

  // LinkedIn pulls the title, description, and image from the page's Open Graph meta tags when sharing a link.
  // See ActionPageSEO.tsx for meta tags
  const handleLinkedInShare = useCallback(() => {
    const linkedInShareURL = `https://www.linkedin.com/sharing/share-offsite/?url=${encodedEventUrl}`;
    window.open(linkedInShareURL, '_blank');
  }, [encodedEventUrl]);

  // Twitter pulls the title, description, and image from the page's Open Graph meta tags when sharing a link.
  // Tweet content is passed directly in the share URL via the `text` query string param.
  // See ActionPageSEO.tsx for meta tags
  const handleTwitterShare = useCallback(() => {
    const title = encodeURIComponent(
      twitterSocialShareTitle ?? facebookSocialShareTitle ?? actionPage?.event?.name ?? ''
    );
    const description = encodeURIComponent(
      twitterSocialShareDescription ?? facebookSocialShareDescription ?? ''
    );
    const twitterShareURL = `https://x.com/intent/post?url=${encodedEventUrl}&text=${title}%20-%20${description}`;
    window.open(twitterShareURL, '_blank');
  }, [
    actionPage,
    encodedEventUrl,
    facebookSocialShareDescription,
    facebookSocialShareTitle,
    twitterSocialShareDescription,
    twitterSocialShareTitle,
  ]);

  return (
    <Popover placement="bottom-end">
      <PopoverTrigger asChild>
        <Button
          className="ml-0 mt-4 min-w-[84px] sm:ml-4 sm:mt-2"
          leftIcon={<ShareIcon />}
          variant="secondary"
        >
          {t('share')}
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="z-[1300] rounded-xl bg-neutral-0 p-4 pt-10 shadow-[0px_14px_32px_rgba(44,58,65,0.15)]"
        width="auto"
      >
        <div className="w-[300px]">
          <div className="absolute right-0 top-0.5">
            <PopoverClose icon={<CloseIcon className="w-[16px]" />} variant="icon" />
          </div>

          <div className="flex justify-between">
            <div className={SHARE_ICON_CLASSES}>
              <Button
                className="!h-[34px] !pe-0 !ps-0"
                icon={<FacebookShareIcon className="w-[34px]" />}
                onClick={handleFacebookShare}
                variant="icon"
              />
            </div>

            <div className={SHARE_ICON_CLASSES}>
              <Button
                className="!h-[26px] !pe-0 !ps-0"
                icon={<XShareIcon className="w-[26px]" />}
                onClick={handleTwitterShare}
                variant="icon"
              />
            </div>

            <div className={SHARE_ICON_CLASSES}>
              <Button
                className="!h-[30px] !pe-0 !ps-0"
                icon={<LinkedInShareIcon className="w-[30px]" />}
                onClick={handleLinkedInShare}
                variant="icon"
              />
            </div>
          </div>

          <div className="pt-6">
            <Paragraph>Or copy link:</Paragraph>
            <div className="relative">
              <InputControl
                className="mt-1 text-ellipsis pr-16 !text-neutral-600"
                formControlProps={{
                  className: '!mb-0',
                }}
                isReadOnly
                name="sharePageLink"
                value={eventUrl}
                variant="unstyled"
              />
              <Button
                className="!absolute right-0 top-3 cursor-pointer text-blue-400"
                onClick={onCopyPageURL}
                variant="link"
              >
                {hasCopiedPageUrl ? 'Copied' : 'Copy'}
              </Button>
            </div>
          </div>
        </div>
      </PopoverContent>
    </Popover>
  );
};

